import asyncio
import websockets
import json
from collections import defaultdict

class Player:
    def __init__(self, username):
        self.username = username
        self.inventory = defaultdict(int)

    def add_item(self, item, quantity):
        self.inventory[item] += quantity

    def remove_item(self, item, quantity):
        if self.inventory[item] >= quantity:
            self.inventory[item] -= quantity
            return True
        return False

class GameServer:
    def __init__(self):
        self.players = {}
        self.connected_clients = {}

    async def handler(self, websocket, path):
        username = await websocket.recv()
        self.players[username] = Player(username)
        self.connected_clients[username] = websocket

        try:
            async for message in websocket:
                await self.handle_message(username, message)
        finally:
            await self.disconnect_player(username)

    async def handle_message(self, username, message):
        data = json.loads(message)
        if data["action"] == "trade":
            await self.handle_trade(username, data["from_item"], data["to_player"], data["to_item"], data["quantity"])

    async def handle_trade(self, from_username, from_item, to_username, to_item, quantity):
        if to_username not in self.players:
            return await self.send_message(from_username, {"error": "Player not found"})

        from_player = self.players[from_username]
        to_player = self.players[to_username]

        if from_player.remove_item(from_item, quantity):
            to_player.add_item(from_item, quantity)
            await self.send_message(from_username, {"success": f"Traded {quantity} {from_item} to {to_username}"})
            await self.send_message(to_username, {"success": f"Received {quantity} {from_item} from {from_username}"})
        else:
            await self.send_message(from_username, {"error": "Insufficient items"})

    async def disconnect_player(self, username):
        if username in self.players:
            del self.players[username]
            del self.connected_clients[username]

    async def send_message(self, username, message):
        if username in self.connected_clients:
            await self.connected_clients[username].send(json.dumps(message))

    async def start_server(self):
        async with websockets.serve(self.handler, "localhost", 6789):
            await asyncio.Future()  # run forever

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.start_server())